	[ModelAds.TYPE_ADS_201] = true,
	[ModelAds.TYPE_ADS_202] = true,
}

--- 重置类型
--- 每日 每日0点时重置刷新次数
ModelAds.RESETTYPE_ADS_1 = 1
--- 每月 每个自然月跨月时重置刷新次数
ModelAds.RESETTYPE_ADS_2 = 2
--- 每周 每个自然周跨周时重置刷新次数
