--模块初始化入口
--注册事件监听
--注册协议监听
--预处理数据
function ModelAds:OnModelInit()
	---@type table<number,StructAdsViewInfo> 广告列表数据
	self._adsInfoMap = {}

	self:InitAdShopRefs()

	--- 广告商城
	self:ModelNetMsgRecv(LProtoIds.AdsCallBackResp, function(...)
		self:OnAdsCallBackResp(...)--刷新对应的广告记录
	end)
	self:ModelNetMsgRecv(LProtoIds.AdsViewInfoResp, function(...)
		self:OnAdsViewInfoResp(...)--观看广告的数据记录
	end)


	self:ModelEventRecv(EventNames.ADSSHOP_OPEN_FINISH,function(...) self:OnAdsShopOpenFinish(...) end)
	self:ModelEventRecv(EventNames.ADSSHOP_OPEN_ERROR,function(...) self:OnAdsShopOpenError(...) end)
end

--在协议数据处理完之后需要调用finish
function ModelAds:OnModelRequest()
	self:ModelFinish()
end


function ModelAds:InitAdShopRefs()
	local initAdShopMap = {}
	local initMethodAdShopMap = {}
	for k,v in pairs(GameTable.AdShopRef) do
		local type = v.type
		local configByModule1Data = self:ParseConfigByModule1(v)
		local data = {
			refId = k,
			moduleRefId = configByModule1Data.refId,
			type = type,
			configByModule1 = v.configByModule1,
			configByModule1Data = configByModule1Data,
			configByModule2 = v.configByModule2,
			configByModule2Data = self:ParseConfigByModule2(v),
			resetType = v.resetType,
			times = configByModule1Data.times,
			redPointConfig = v.redPointConfig,
		}
		initAdShopMap[k] = data

		local methodAdShops = initMethodAdShopMap[type]
		if not methodAdShops then
			methodAdShops = {}
			initMethodAdShopMap[type] = methodAdShops
		end
		table.insert(methodAdShops,data)
	end
	self._initAdShopMap = initAdShopMap
	self._initMethodAdShopMap = initMethodAdShopMap
end

---@param ref V_AdShopRef
function ModelAds:ParseConfigByModule1(ref)
	local configByModule1 = string.split(ref.configByModule1,"=")
	local type = ref.type
	if type == ModelAds.TYPE_ADS_101 then
		return {
			refId = checknumber(configByModule1[1]),
			times = checknumber(configByModule1[2]),
		}
	elseif type == ModelAds.TYPE_ADS_201 then
		return {
			refId = checknumber(configByModule1[1]),
			times = checknumber(configByModule1[2]),
			sort = checknumber(configByModule1[3]),
		}
	elseif type == ModelAds.TYPE_ADS_202 then
		return {
			refId = checknumber(configByModule1[1]),
			times = checknumber(configByModule1[2]),
		}
	elseif type == ModelAds.TYPE_ADS_301 then
		return {
			refId = checknumber(configByModule1[1]),
			times = checknumber(configByModule1[2]),
		}
	elseif type == ModelAds.TYPE_ADS_401 then
		return {
			refId = checknumber(configByModule1[1]),
			times = checknumber(configByModule1[2]),
		}
	elseif type == ModelAds.TYPE_ADS_501 then
		return {
			refId = checknumber(configByModule1[1]),
			times = checknumber(configByModule1[2]),
		}
	else
		if LOG_INFO_ENABLED then
			printInfoNR2("广告变现","configByModule1 未定义解析类型,type = " .. type)
		end
	end
end

---@param ref V_AdShopRef
function ModelAds:ParseConfigByModule2(ref)
	local configByModule2 = ref.configByModule2
	if string.isempty(configByModule2) then
		if LOG_INFO_ENABLED then
			printInfoNR2("广告变现","configByModule2 数据为空,type = " .. ref.type)
		end
		return nil
	end

	local type = ref.type
	if type == ModelAds.TYPE_ADS_201 then
		return {
			reward = LxDataHelper.ParseItem(configByModule2),
		}
	else
		if LOG_INFO_ENABLED then
			printInfoNR2("广告变现","configByModule2 未定义解析类型,type = " .. type)
		end
	end
end

function ModelAds:GetConfigTimes(refId)
	local config = self._initAdShopMap[refId]
	if not config then return end

	local configByModule1Data = config.configByModule1Data
	return configByModule1Data and configByModule1Data.times
end



-- 观看广告回调
function ModelAds:OnAdsCallBackReq(refId,callback,skip,watchTime)
	local pb = LProtoHelper.CreateProto(LProtoIds.AdsCallBackReq)
	pb.refId = refId

	pb.callback = callback or ""

	skip = skip and true or false
	pb.skip = skip

	pb.watchTime = watchTime or 0
	SendMessage(pb,LProtoIds.AdsCallBackReq)
end

---刷新对应的广告记录
function ModelAds:OnAdsCallBackResp(pb)
	self:SaveAdsInfo(pb.info)
	FireEvent(EventNames.REFRESH_ADS)
end

function ModelAds:OnAdsViewInfoResp(pb)
	self:SaveAdsInfos(pb.infos)
	self:InitAdsViewInfoRedPoint()
	FireEvent(EventNames.REFRES_ADSVIEW_INFO)
end

function ModelAds:SaveAdsInfos(infos)
	infos = infos or {}
	for i,v in ipairs(infos) do
		self:SaveAdsInfo(v)
	end
end

function ModelAds:SaveAdsInfo(pb)
	local adsInfoMap = self._adsInfoMap
	if not adsInfoMap then
		adsInfoMap = {}
		self._adsInfoMap = adsInfoMap
	end
	local refId = pb.refId
	---@type StructAdsViewInfo
	local adsInfo = adsInfoMap[refId]
	if not adsInfo then
		adsInfo = StructAdsViewInfo:New()
		adsInfoMap[refId] = adsInfo
	end
	adsInfo:CreateByPb(pb)
end


function ModelAds:OnAdsShopOpenFinish()
	if not self._openAdInfo then return end

	local openAdInfo = self._openAdInfo
	self:DoAdsCallBackReq(openAdInfo)
	local data = {
		["adShop_id"] = tostring(openAdInfo.refId),
		["adShop_valid"] = "1",
	}
	local attr1 = JSON.encode(data)
	gLxTKData:OnTAClientEventReq(LxTKData.ADSHOP_EFF, "广告商城", attr1)

	self._openAdInfo = nil
end


function ModelAds:OnAdsShopOpenError()
	local openAdInfo = self._openAdInfo
	if openAdInfo then
		local data = {
			["adShop_id"] = tostring(openAdInfo.refId),
			["adShop_valid"] = "0",
		}
		local attr1 = JSON.encode(data)
		gLxTKData:OnTAClientEventReq(LxTKData.ADSHOP_EFF, "广告商城", attr1)
	end
	self._openAdInfo = nil
end

function ModelAds:DoAdsCallBackReq(openAdInfo)
	if not openAdInfo then return end

	self:OnAdsCallBackReq(openAdInfo.refId,openAdInfo.callback,openAdInfo.skip,openAdInfo.watchTime)
end


function ModelAds:CheckHasAdsInfo(refId)
	local adsInfo = self:GetAdsViewInfo(refId)
	return adsInfo ~= nil
end

---@return StructAdsViewInfo | nil
function ModelAds:GetAdsViewInfo(refId)
	if not self._adsInfoMap then return end
	return self._adsInfoMap[refId]
end

---@return number 已观看次数
function ModelAds:GetAdViewCount(refId)
	local adsInfo = self:GetAdsViewInfo(refId)
	return adsInfo and adsInfo.viewCount or 0
end

function ModelAds:GetHasAdViewCount(params)
	if not self:CheckShowADBtn() then return end

	local config = self:GetAdConfigByParam(params)
	if not config then return end

	local adRefId = config.refId
	local configTimes = self:GetConfigTimes(adRefId)
	local viewCount = self:GetAdViewCount(adRefId)
	return configTimes - viewCount
end

function ModelAds:CheckHasAdViewCount(params)
	if not self:CheckShowADBtn() then return end

	local config = self:GetAdConfigByParam(params)
	if not config then return false end

	local lostCnt = self:GetHasAdViewCount(params)
	return lostCnt and lostCnt > 0 or false
end

--- 检查是否显示按钮
function ModelAds:CheckNeedShowAdBtn(params)
	--- 没有次数了
	if not self:CheckHasAdViewCount(params) then return false end

	local adMethodId = params.adMethodId
	if adMethodId == ModelAds.TYPE_ADS_101 then
		if gModelGuild:GetBHaveGuild() then
			local price = gModelGuild:GetGuildDonatePrice(params.refId)
			if not price then return false end

			if not gModelGeneral:CheckItemEnough(price.itemId,price.itemNum) then
				return true
			end
		end
	elseif adMethodId == ModelAds.TYPE_ADS_201 then
	elseif adMethodId == ModelAds.TYPE_ADS_202 then
	elseif adMethodId == ModelAds.TYPE_ADS_301 then
		--- 当对应的祷告项 次数不足或道具不足 时
		local refId = params.refId
		if refId and refId > 0 then
			local emptyCnt = true
			---@type StructGoldBuy
			local data = gModelGoldBuy:GetGoldItemByRefId(refId)
			if data then
				emptyCnt = data.remainTime < 1
			end
			local noEnoughItem = false
			local basicsRef = gModelGoldBuy:GetGoldBuyBasicsRefById(refId)
			local buyNeed = basicsRef and basicsRef.buyNeed
			if not string.isempty(buyNeed) then
				local buyNeedArr = string.split(buyNeed, "=")
				local hasNum = gModelItem:GetNumByRefId(checknumber(buyNeedArr[1]))
				if hasNum < checknumber(buyNeedArr[2]) then
					noEnoughItem = true
				end
			end
			return emptyCnt or noEnoughItem
		end
	elseif adMethodId == ModelAds.TYPE_ADS_401 then
		--- 配置401功能模块且有该弹窗礼包ID的配置，且有次数即可
		return true
	elseif adMethodId == ModelAds.TYPE_ADS_501 then
		--- 有次数就返回 true
		return true
	end
	return false
end


function ModelAds:CheckShowADBtn()
	if LGameSettings.platformRegion ~= LRegionConst.RUS then return false end
	return gModelFunctionOpen:CheckIsOpened(18009000)
end


function ModelAds:FindConfigByMethodIdAndRefId(adMethodId,refId)
	if not self:CheckShowADBtn() then return end

	local methodAdShops = self._initMethodAdShopMap[adMethodId]
	if not methodAdShops or #methodAdShops < 1 then return end

	for i,v in ipairs(methodAdShops) do
		if v.moduleRefId == refId then
			return v
		end
	end
end


function ModelAds:FindConfigsByMethodIdAndRefId(adMethodId,refId)
	if not self:CheckShowADBtn() then return end

	local methodAdShops = self._initMethodAdShopMap[adMethodId]
	if not methodAdShops or #methodAdShops < 1 then return end

	local list = {}
	for i,v in ipairs(methodAdShops) do
		if v.moduleRefId == refId then
			table.insert(list,v)
		end
	end
	return list
end

function ModelAds:CheckHasAdConfig(refId)
	return self._initAdShopMap[refId]
end

function ModelAds:GetAdConfigByParam(param)
	return self:FindConfigByMethodIdAndRefId(param.adMethodId,param.refId)
end

function ModelAds:GetAdConfigsByParam(param)
	return self:FindConfigsByMethodIdAndRefId(param.adMethodId,param.refId)
end

function ModelAds:CheckHasAdConfigByParam(param)
	local config = self:GetAdConfigByParam(param)
	return config ~= nil
end

function ModelAds:OpenAd(data)
	if not data then return end

	if self._openAdInfo then
		--- 已经打开广告
		return
	end

	if gModelNormalActivity:CheckHasAdPrivilegeActive() then
		data.skip = true
		self:DoAdsCallBackReq(data)
		return
	end

	local refId = data.refId
	local configTimes = self:GetConfigTimes(refId)
	if not configTimes or configTimes < 1 then
		--- 无配置
		return
	end

	local viewCount = self:GetAdViewCount(refId)
	if viewCount >= configTimes then
		--- 观影次数达到上限
		return
	end

	self._openAdInfo = data

	FireEvent(EventNames.ADSSHOP_OPEN_INIT)

	gLSdkImpl:CallMethod(LSdkMethod.ShowRewardAdview)
end


function ModelAds:OpenAdByCommonTips(wndId,params)
	params = params or {}

	local openADFunc = params.openADFunc
	local config = self:GetAdConfigByParam(params)
	if not config then
		if openADFunc then openADFunc() end
		return
	end

	local para
	local adRefId = config.refId
	local adMethodId = params.adMethodId
	if adMethodId == ModelAds.TYPE_ADS_101 then
		local price = gModelGuild:GetGuildDonatePrice(params.refId)
		if price then
			local itemName = gModelItem:GetNameByRefId(price.itemId)
			para = {string.replace("#a1#*#a2#",itemName,LUtil.NumberCoversion(price.itemNum))}
		end
	elseif adMethodId == ModelAds.TYPE_ADS_201 then
		local reward = params.reward
		if reward and #reward > 0 then
			local item = reward[1]
			local itemName = gModelItem:GetNameByRefId(item.itemId)
			para = {string.replace("#a1#*#a2#",itemName,LUtil.NumberCoversion(item.itemNum))}
		end
	elseif adMethodId == ModelAds.TYPE_ADS_202 then
		local shopId = params.shopId
		if shopId and shopId > 0 then
			para = {ccLngText(gModelShop:GetShopName(shopId))}
		end
	elseif adMethodId == ModelAds.TYPE_ADS_301 then
		local refId = params.refId
		if refId and refId > 0 then
			local basicsRef = gModelGoldBuy:GetGoldBuyBasicsRefById(refId)
			if basicsRef then
				para = {ccLngText(basicsRef.name)}
			end
		end
	elseif adMethodId == ModelAds.TYPE_ADS_401 then
		local giftRefId = params.giftRefId
		if giftRefId and giftRefId > 0 then
			local giftRef = gModelPopupGift:GetPopupGiftRefByRefId(giftRefId)
			if giftRef then
				para = {ccLngText(giftRef.giftName)}
			end
		end
	elseif adMethodId == ModelAds.TYPE_ADS_501 then
		local callRefId = params.callRefId
		if callRefId and callRefId > 0 then
			local refData = gModelCallHero:GetCallRefByRefId(callRefId)
			if refData then
				para = {ccLngText(refData.typeName)}
			end
		end
	end
	gModelGeneral:OpenUIOrdinTips({
		refId = wndId,
		para = para,
		func = openADFunc,
		privilegeStatus = 1,
		jumpCB = params.jumpCB,
	}, true)
end


function ModelAds:SetAdBtnName(params)
	local config = self:GetAdConfigByParam(params)
	if not config then return "" end

	local textStr
	local textId = params.textId
	if textId and textId > 0 then
		textStr = ccClientText(textId)
	else
		textStr = "#a1#/#a2#"
	end
	local refId = config.refId
	local viewCount = self:GetAdViewCount(refId)
	local configTimes = self:GetConfigTimes(refId)
	local loseTimes = configTimes - viewCount
	return string.replace(textStr,loseTimes,configTimes)
end



function ModelAds:InitAdsViewInfoRedPoint()
	if not self:CheckShowADBtn() then return end

	if self._initRP then return end

	self._initRP = true

	local adsInfoMap = self._adsInfoMap
	if not adsInfoMap then
		adsInfoMap = {}
		self._adsInfoMap = adsInfoMap
	end

	local shopIdMap = {}
	local shopCnt = 0
	local hasRPChangeCnt = 0
	local configByModule1Data,times
	local initAdShopMap = self._initAdShopMap
	for k,v in pairs(initAdShopMap) do
		configByModule1Data = v.configByModule1Data
		times = configByModule1Data and configByModule1Data.times or 0
		if times > 0 then
			local needCheck = true
			local adsInfo = adsInfoMap[k]
			if adsInfo then
				if times - adsInfo.viewCount < 1 then
					needCheck = false
				end
			end
			local type = v.type
			if needCheck then
				if type == ModelAds.TYPE_ADS_202 then
					--- refreshNeed 为空表示不可手动刷新
					--[[			当该商店本来就有“手动刷新”时：
                                    当商店存在“免费手动刷新”或“付费手动刷新”，则免费次数和付费次数均用完后刷新按钮替换为“广告”按钮
                                    当该商店本身不支持“手动刷新”时，需按下图样式显示：
                                    与“手动刷新”一致，商品列表可视区域缩短，增加一栏空白位置]]
					local shopId = configByModule1Data.moduleRefId
					local netData = gModelShop:GetShopNetData(shopId)
					if netData then
						local refresh = netData.refresh
						if refresh then
							local refreshCountMax = gModelShop:GetShopMaxRefreshTime(shopId)
							if refresh.costNum < refreshCountMax then
								needCheck = false
							end
						end
					end
				elseif type == ModelAds.TYPE_ADS_301 or type == ModelAds.TYPE_ADS_101 then
					needCheck = self:CheckNeedShowAdBtn({
						adMethodId = type,refId = v.moduleRefId,
					})
				end
			end
			if needCheck then
				local redPointConfig = v.redPointConfig
				if redPointConfig and redPointConfig > 0 then
					local isShopAbout = ads_shop_map[type]
					if isShopAbout then
						shopCnt = shopCnt + 1
						local rpShops = shopIdMap[redPointConfig]
						if not rpShops then
							rpShops = {}
							shopIdMap[redPointConfig] = rpShops
						end
						table.insert(rpShops,v.moduleRefId)
					else
						if gModelRedPoint:SetAdsRedPoint(redPointConfig) then
							hasRPChangeCnt = hasRPChangeCnt + 1
						end
					end
				end
			end
		end
	end
	if shopCnt > 0 then
		for rpId,shops in pairs(shopIdMap) do
			local shopStr = table.concat(shops,"|")
			if gModelRedPoint:SetAdsShopRedPoint(rpId,shopStr) then
				hasRPChangeCnt = hasRPChangeCnt + 1
			end
		end
	end
	if hasRPChangeCnt > 0 then
		FireEvent(EventNames.ON_RED_CHANGE)
	end
end


